/**
 * CMSVersion values as defined in RFC 5652.
 *
 * @asn
 * ```asn
 * CMSVersion ::= INTEGER  { v0(0), v1(1), v2(2), v3(3), v4(4), v5(5) }
 * ```
 */
export type CMSVersion = number;
export declare const CMSVersion: {
    readonly v0: 0;
    readonly v1: 1;
    readonly v2: 2;
    readonly v3: 3;
    readonly v4: 4;
    readonly v5: 5;
};
